function requireArray(value, name) {
  if (!Array.isArray(value) || value.some((item) => typeof item !== "string")) {
    throw new TypeError(name + " must be a string array");
  }
  return [...value];
}

export function buildPolicy(defaults, overlay = {}) {
  const defaultRegions = requireArray(defaults.allowedRegions, "allowedRegions");
  const allowedRegions = Array.isArray(overlay.allowedRegions) && overlay.allowedRegions.length > 0
    ? requireArray(overlay.allowedRegions, "allowedRegions")
    : defaultRegions;

  const requiredScopes = Object.prototype.hasOwnProperty.call(overlay, "requiredScopes")
    ? requireArray(overlay.requiredScopes, "requiredScopes")
    : requireArray(defaults.requiredScopes, "requiredScopes");

  return Object.freeze({
    allowedRegions: Object.freeze(allowedRegions),
    requiredScopes: Object.freeze(requiredScopes)
  });
}

