function deny(reason) {
  return Object.freeze({ allowed: false, reason });
}

export function authorizeRequest(policy, request, route) {
  if (!policy.allowedRegions.includes(request.region)) {
    return deny("region_not_allowed");
  }

  const granted = new Set(request.scopes);
  const recognized = [...policy.requiredScopes, ...route.anyOfScopes];
  if (recognized.length > 0 && !recognized.some((scope) => granted.has(scope))) {
    return deny("scope_not_granted");
  }

  return Object.freeze({ allowed: true, reason: "allowed" });
}

