import { buildPolicy } from "./policy-config.mjs";
import { authorizeRequest } from "./authorize-request.mjs";

const REPORT_ROUTE = Object.freeze({
  anyOfScopes: Object.freeze(["report:read", "report:admin"])
});

export class ReportService {
  #policy;

  constructor({ defaults, overlay }) {
    this.#policy = buildPolicy(defaults, overlay);
  }

  readSummary(request) {
    const decision = authorizeRequest(this.#policy, request, REPORT_ROUTE);
    if (!decision.allowed) {
      return { status: 403, code: decision.reason };
    }
    return {
      status: 200,
      report: { tenant: request.tenant, region: request.region }
    };
  }
}

