import test from "node:test";
import assert from "node:assert/strict";

import { ReportService } from "../src/report-service.mjs";

const defaults = {
  allowedRegions: ["us-west", "us-east"],
  requiredScopes: ["tenant:verified"]
};

test("explicit regional overlay and complete scopes allow a report", () => {
  const service = new ReportService({ defaults, overlay: { allowedRegions: ["eu-central"] } });
  const response = service.readSummary({
    tenant: "acme",
    region: "eu-central",
    scopes: ["tenant:verified", "report:read"]
  });
  assert.equal(response.status, 200);
  assert.deepEqual(response.report, { tenant: "acme", region: "eu-central" });
});

test("a region outside an explicit overlay is denied", () => {
  const service = new ReportService({ defaults, overlay: { allowedRegions: ["eu-central"] } });
  const response = service.readSummary({
    tenant: "acme",
    region: "us-west",
    scopes: ["tenant:verified", "report:admin"]
  });
  assert.equal(response.status, 403);
  assert.equal(response.code, "region_not_allowed");
});

test("omitting the regional overlay retains defaults", () => {
  const service = new ReportService({ defaults, overlay: {} });
  const response = service.readSummary({
    tenant: "acme",
    region: "us-east",
    scopes: ["tenant:verified", "report:read"]
  });
  assert.equal(response.status, 200);
});

test("a principal with no recognized scope is denied", () => {
  const service = new ReportService({ defaults, overlay: {} });
  const response = service.readSummary({
    tenant: "acme",
    region: "us-west",
    scopes: ["profile:read"]
  });
  assert.equal(response.status, 403);
});
